const data = $input.first().json;
const licitaciones = data.results || [];

if (licitaciones.length === 0) {
  return [{ json: { continuar: false, total: 0, mensaje: 'No hay licitaciones en la BD para testear.' } }];
}

return licitaciones.map(l => ({
  json: {
    continuar: true,
    id: l.id,
    expediente_id: l.expediente_id,
    titulo: l.titulo,
    importe_base: l.importe_base,
    provincia: l.provincia,
    organismo: l.organismo_nombre,
    fecha_limite: l.fecha_limite_oferta,
    dias_restantes: l.dias_restantes,
    url: `http://django:8000/api/v1/licitacions/${l.id}/`,
    pdf_disponible: l.pdf_descargado,
    total_licitaciones: licitaciones.length
  }
}));

const l = $json;

const importe_fmt = l.importe_base
  ? parseFloat(l.importe_base).toLocaleString('es-ES', { minimumFractionDigits: 0 })
  : 'N/D';

const plazo_txt = l.dias_restantes !== null && l.dias_restantes !== undefined
  ? `${l.dias_restantes} días`
  : 'sin fecha';

const prompt = `Analiza la siguiente licitación pública española y genera un resumen ejecutivo de UNA sola frase (máximo 80 palabras) destacando el aspecto más relevante para una empresa constructora.\n\nLicitación:\n- Título: ${l.titulo}\n- Organismo: ${l.organismo || 'Desconocido'}\n- Provincia: ${l.provincia || 'N/D'}\n- Importe base: ${importe_fmt} EUR\n- Plazo de presentación: ${plazo_txt}\n\nResponde ÚNICAMENTE con el resumen, sin introducción ni explicación adicional.`;

return [{ json: { ...l, prompt, importe_fmt, plazo_txt } }];

const prev = $('✏️ Preparar prompt Ollama').item.json;
const ollamaResp = $input.item.json;

if (!prev.id) return [];

const resumen_ia = (ollamaResp.response || '').trim();

return [{
  json: {
    ...prev,
    resumen_ia,
    ok: resumen_ia.length > 0
  }
}];

const items = $input.all();

if (items.length === 0) {
  return [{ json: { mensaje: 'Ninguna licitación procesada.', total: 0 } }];
}

const lines = items.slice(0, 10).map((item, i) => {
  const l = item.json;
  const importe_txt = l.importe_fmt ? `${l.importe_fmt} EUR` : 'N/D';
  return `${i + 1}. *${l.titulo?.substring(0, 70) || 'N/D'}*\n   📍 ${l.provincia || 'N/D'} | 💶 ${importe_txt} | ⏰ ${l.plazo_txt || 'N/D'}\n   _${l.resumen_ia?.substring(0, 100) || '—'}_`;
});

const resto = items.length > 10 ? `\n... y ${items.length - 10} licitaciones más.` : '';

const mensaje = `🧪 *[TEST] CONSTRUTECH-IA*\n📅 ${new Date().toLocaleDateString('es-ES')}\n✅ ${items.length} licitaciones analizadas (sin marcar como revisadas)\n\n${lines.join('\n\n')}${resto}`;

return [{ json: { mensaje, total: items.length } }];

